// 计算所有分类
const categories = computed(() => {
  const allCategories = new Set<string>();
  systemAgents.value.forEach(agent => {
    agent.group.forEach(group => allCategories.add(group));
  });
  
  // 添加"所有"分类
  const categoryList = [{ name: '所有', count: systemAgents.value.length }];
  
  // 添加其他分类
  allCategories.forEach(category => {
    const count = systemAgents.value.filter(agent => agent.group.includes(category)).length;
    categoryList.push({ name: category, count });
  });
  
  return categoryList;
});

// 过滤助手
const filteredAgents = computed(() => {
  let agents = systemAgents.value;
  
  // 按分类过滤
  if (currentCategory.value !== '所有') {
    agents = agents.filter(agent => agent.group.includes(currentCategory.value));
  }
  
  // 按搜索词过滤
  if (searchQuery.value) {
    const query = searchQuery.value.toLowerCase();
    agents = agents.filter(agent => 
      agent.name.toLowerCase().includes(query) || 
      agent.description.toLowerCase().includes(query) ||
      agent.group.some(group => group.toLowerCase().includes(query))
    );
  }
  
  return agents;
});

// 打开助手详情模态框
const openAgentModal = (agent: any) => {
  selectedAgent.value = agent;
  showModal.value = true;
};

// 添加到智能体工坊
const addToAgentWorkshop = async () => {
  if (selectedAgent.value) {
    try {
      // 调用persona store的createPersona方法添加助手到智能体工坊
      await personaStore.createPersona({
        name: selectedAgent.value.name,
        title: selectedAgent.value.name,
        bio: selectedAgent.value.description,
        theories: selectedAgent.value.group,
        stance: 'Neutral',
        system_prompt: selectedAgent.value.prompt,
        is_public: false,
        avatar: selectedAgent.value.emoji
      });
      
      showToastMessage('助手已成功添加到智能体工坊');
      showModal.value = false;
      
      // 跳转到智能体工坊页面
      setTimeout(() => {
        router.push('/personas');
      }, 1000);
    } catch (error) {
      console.error('添加助手到智能体工坊失败:', error);
      showToastMessage('添加助手到智能体工坊失败，请重试');
    }
  }
};

// 显示提示信息
const showToastMessage = (message: string) => {
  toastMessage.value = message;
  showToast.value = true;
  setTimeout(() => {
    showToast.value = false;
  }, 3000);
};

